/**
 * @summary Get recent consultations for dashboard
 */
export const getGetRecentConsultationsUrl = (
  params?: GetRecentConsultationsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/recent?${stringifiedParams}`
    : `/api/dashboard/recent`;
};

export const getRecentConsultations = async (
  params?: GetRecentConsultationsParams,
  options?: RequestInit,
): Promise<Consultation[]> => {
  return customFetch<Consultation[]>(getGetRecentConsultationsUrl(params), {
    ...options,
    method: "GET",
  });
};

